import axios from 'axios';

const BASE_URL = 'http://localhost:5000/api/ai';

/**
 * Ghi nhận thói quen người dùng: play | search | like
 * Gọi "ngầm" (fire-and-forget), không chặn UI nếu lỗi.
 */
export const logActivity = async ({ userId, type, songId, songTitle, artist, keyword }) => {
  if (!userId) return; // Chỉ ghi nhận khi người dùng đã đăng nhập
  try {
    await axios.post(`${BASE_URL}/activity`, { userId, type, songId, songTitle, artist, keyword });
  } catch (err) {
    console.error('Lỗi ghi nhận thói quen:', err.message);
  }
};

/**
 * Lấy danh sách gợi ý nhạc do AI Agent (Gemini 2.5 Pro) phân tích.
 * Trả về: { reason, mood, criteria, recommendations }
 */
export const getAIRecommendations = async (userId) => {
  const res = await axios.get(`${BASE_URL}/recommendations/${userId}`);
  return res.data;
};
